class Solution:
    def recoverMaxHeap(self, nums: list[int]) -> None:
        unique_elements = set(nums)
        heap = []
        for num in unique_elements:
            heap.append(num)
            self.heapifyUp(heap, len(heap) - 1)

    def heapifyUp(self, heap, index):
        parent = (index - 1) // 2
        if index > 0 and heap[parent] < heap[index]:
            heap[parent], heap[index] = heap[index], heap[parent]
            self.heapifyUp(heap, parent)

    def main(self) -> None:
        nums = [2, 3, 3, 5]
        self.recoverMaxHeap(nums)

        print(' '.join(map(str, nums)))

