class Solution {
public:
    void recoverMaxHeap(std::vector<int>& nums) {
        uniqueElements = getUniqueElements(nums);
        for (int num : uniqueElements) {
            insertIntoHeap(nums, num);
        }
    }

    std::vector<int> getUniqueElements(const std::vector<int>& nums) {
        std::set<int> uniqueElements;
        for (int num : nums) {
            uniqueElements.insert(num);
        }
        return std::vector<int>(uniqueElements.begin(), uniqueElements.end());
    }

    void insertIntoHeap(std::vector<int>& nums, int num) {
        nums.push_back(num);
        maxHeapify(nums, nums.size() - 1);
    }

    void maxHeapify(std::vector<int>& nums, int index) {
        int parent = (index - 1) / 2;
        if (index > 0 && nums[parent] < nums[index]) {
            nums[parent] = nums[index];
            maxHeapify(nums, parent);
        }
    }

    int main() {
        std::vector<int> nums = {2, 3, 3, 5};
        recoverMaxHeap(nums);

        for (int num : nums) {
            std::cout << num << ' ';
        }
        std::cout << '
';
        return 0;
    }
};
